#include <stdio.h>

int main() {
    int T, M, N;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        scanf("%d %d", &M, &N);
        int matrix[M][N];
        int dp[M][N];
        for (int i = 0; i < M; ++i) {
            for (int j = 0; j < N; ++j) {
                scanf("%d", &matrix[i][j]);
                dp[i][j] = 0;
            }
        }
        long long ans = 0; // answer can be up to M*N*min(M,N)
        for (int i = 0; i < M; ++i) {
            for (int j = 0; j < N; ++j) {
                if (matrix[i][j] == 1) {
                    if (i == 0 || j == 0) {
                        dp[i][j] = 1;
                    } else {
                        int m = dp[i-1][j];
                        if (dp[i][j-1] < m) m = dp[i][j-1];
                        if (dp[i-1][j-1] < m) m = dp[i-1][j-1];
                        dp[i][j] = m + 1;
                    }
                    ans += (dp[i][j] * (dp[i][j] + 1)) / 2;
                }
            }
        }
        printf("%lld\n", ans);
    }
    return 0;
}

