      matrix[i][j] = Number(input[idx++]);
    }
  }
  const dp = Array.from({ length: M }, () => Array(N).fill(0));
  let ans = 0;
  for (let i = 0; i < M; i++) {
    for (let j = 0; j < N; j++) {
      if (matrix[i][j] === 1) {
        if (i === 0 || j === 0) dp[i][j] = 1;
        else dp[i][j] = Math.min(dp[i-1][j], dp[i][j-1], dp[i-1][j-1]) + 1;
